@namespace Lumeo
@inject Lumeo.Services.IComponentInteropService Interop

@{
    var context = new AccordionContext(
        Type,
        OpenItems,
        EventCallback.Factory.Create<string>(this, ToggleItem),
        RegisterTrigger,
        ReplaceTrigger,
        UnregisterTrigger,
        EventCallback.Factory.Create<(string Value, int Delta, bool ToEdge, bool Last)>(this, MoveFocus));
}

<div class="@CssClass" @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public AccordionType Type { get; set; } = AccordionType.Single;

    /// <summary>Initial open items for the <b>uncontrolled</b> usage. Ignored
    /// once <see cref="Value"/> / <see cref="Values"/> drive the component.</summary>
    [Parameter] public List<string>? DefaultValues { get; set; }

    /// <summary>
    /// Controlled open item for <see cref="AccordionType.Single"/>. When non-null
    /// the accordion is controlled — its open state comes entirely from this
    /// parameter and toggles are reported via <see cref="ValueChanged"/> (the
    /// consumer owns the state). Pair with <c>@bind-Value</c>. An empty string
    /// means "all collapsed". Leave null for the uncontrolled behaviour seeded by
    /// <see cref="DefaultValues"/>.
    /// </summary>
    [Parameter] public string? Value { get; set; }

    /// <summary>Two-way callback for <see cref="Value"/> (Single mode).</summary>
    [Parameter] public EventCallback<string> ValueChanged { get; set; }

    /// <summary>
    /// Controlled open items for <see cref="AccordionType.Multiple"/>. When
    /// non-null the accordion is controlled. Pair with <c>@bind-Values</c>.
    /// Leave null for the uncontrolled behaviour seeded by
    /// <see cref="DefaultValues"/>.
    /// </summary>
    [Parameter] public IReadOnlyList<string>? Values { get; set; }

    /// <summary>Two-way callback for <see cref="Values"/> (Multiple mode).</summary>
    [Parameter] public EventCallback<IReadOnlyList<string>> ValuesChanged { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly HashSet<string> _openItems = new();
    private bool _initialized;

    // Ordered trigger registry: value -> (triggerId, disabled). Maintained by
    // AccordionTrigger so roving ArrowUp/Down/Home/End can move focus between
    // triggers in DOM order, skipping disabled ones (WAI-ARIA accordion).
    private readonly List<(string Value, string TriggerId, bool Disabled)> _triggers = new();

    // Controlled when either controlled parameter is supplied (non-null).
    private bool IsControlled => Value is not null || Values is not null;

    // The set the cascade reads from: the controlled parameters when controlled,
    // else the internal uncontrolled set.
    private HashSet<string> OpenItems
    {
        get
        {
            if (!IsControlled) return _openItems;
            var set = new HashSet<string>();
            if (Type == AccordionType.Multiple)
            {
                if (Values is not null)
                    foreach (var v in Values) set.Add(v);
            }
            else if (!string.IsNullOrEmpty(Value))
            {
                set.Add(Value);
            }
            return set;
        }
    }

    private string CssClass => Cx.Merge(Class);

    protected override void OnInitialized()
    {
        if (!_initialized && DefaultValues is { Count: > 0 })
        {
            foreach (var value in DefaultValues)
            {
                _openItems.Add(value);
            }
        }
        _initialized = true;
    }

    private async Task ToggleItem(string value)
    {
        if (IsControlled)
        {
            // Compute the next state from the controlled parameters and report
            // it; never mutate the consumer's source of truth directly.
            var open = OpenItems;
            if (Type == AccordionType.Multiple)
            {
                var next = new List<string>(open);
                if (next.Contains(value)) next.Remove(value);
                else next.Add(value);
                await ValuesChanged.InvokeAsync(next);
            }
            else
            {
                var next = open.Contains(value) ? string.Empty : value;
                await ValueChanged.InvokeAsync(next);
            }
            return;
        }

        if (_openItems.Contains(value))
        {
            _openItems.Remove(value);
        }
        else
        {
            if (Type == AccordionType.Single)
            {
                _openItems.Clear();
            }
            _openItems.Add(value);
        }
        StateHasChanged();
    }

    private void RegisterTrigger(string value, string triggerId, bool disabled)
    {
        var idx = _triggers.FindIndex(t => t.Value == value);
        if (idx >= 0) _triggers[idx] = (value, triggerId, disabled);
        else _triggers.Add((value, triggerId, disabled));
    }

    // Re-key an existing trigger IN PLACE when an item's Value changes at
    // runtime. A naive Unregister(old)+Register(new) would RemoveAt(old index)
    // then Add() the new value to the TAIL, scrambling the registry away from
    // DOM order and corrupting roving ArrowUp/Down/Home/End navigation. Keeping
    // the original slot preserves DOM/declaration order across a Value change.
    private void ReplaceTrigger(string oldValue, string newValue, string triggerId, bool disabled)
    {
        var idx = _triggers.FindIndex(t => t.Value == oldValue);
        if (idx >= 0) _triggers[idx] = (newValue, triggerId, disabled);
        else RegisterTrigger(newValue, triggerId, disabled);
    }

    private void UnregisterTrigger(string value)
    {
        var idx = _triggers.FindIndex(t => t.Value == value);
        if (idx >= 0) _triggers.RemoveAt(idx);
    }

    // Roving focus across triggers. Delta ±1 steps to the next/previous enabled
    // trigger (no wrap, matching Radix); ToEdge focuses the first/last enabled
    // trigger (Home/End). Focus is moved via the interop FocusElement helper.
    private async Task MoveFocus((string Value, int Delta, bool ToEdge, bool Last) args)
    {
        if (_triggers.Count == 0) return;
        string? targetId = null;

        if (args.ToEdge)
        {
            targetId = args.Last
                ? _triggers.LastOrDefault(t => !t.Disabled).TriggerId
                : _triggers.FirstOrDefault(t => !t.Disabled).TriggerId;
        }
        else
        {
            var current = _triggers.FindIndex(t => t.Value == args.Value);
            if (current < 0) return;
            var idx = current;
            for (var i = 0; i < _triggers.Count; i++)
            {
                idx += args.Delta;
                if (idx < 0 || idx >= _triggers.Count) return; // no wrap
                if (!_triggers[idx].Disabled) { targetId = _triggers[idx].TriggerId; break; }
            }
        }

        if (!string.IsNullOrEmpty(targetId))
        {
            try { await Interop.FocusElement(targetId); }
            catch (JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
            catch (InvalidOperationException) { } // prerender
        }
    }

    public enum AccordionType { Single, Multiple }

    public record AccordionContext(
        AccordionType Type,
        HashSet<string> OpenItems,
        EventCallback<string> Toggle,
        Action<string, string, bool> RegisterTrigger,
        Action<string, string, string, bool> ReplaceTrigger,
        Action<string> UnregisterTrigger,
        EventCallback<(string Value, int Delta, bool ToEdge, bool Last)> MoveFocus)
    {
        public bool IsOpen(string value) => OpenItems.Contains(value);
    }
}

@namespace Lumeo

@* `invisible` while closed: content stays mounted for the grid-rows close
   animation, but visibility:hidden removes its focusable children from the
   tab order — aria-hidden alone left links/buttons tabbable inside a panel
   AT can't see. Opacity already flipped instantly, so no visual change. *@
<div id="@ItemContext.ContentId" role="region" aria-labelledby="@ItemContext.TriggerId" class="grid transition-[grid-template-rows] duration-200 ease-out @(IsOpen ? "grid-rows-[1fr] opacity-100" : "grid-rows-[0fr] opacity-0 invisible") @CssClass" @attributes="AdditionalAttributes" aria-hidden="@(IsOpen ? "false" : "true")">
    <div class="overflow-hidden min-h-0">
        <div class="pb-4 pt-0">
            @ChildContent
        </div>
    </div>
</div>

@code {
    [CascadingParameter] public Accordion.AccordionContext Context { get; set; } = default!;
    [CascadingParameter] public AccordionItem.AccordionItemContext ItemContext { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>
    /// Preserved for API compatibility only — Accordion content is now always
    /// mounted to allow the grid-rows close animation to run on collapse, so
    /// this flag is effectively a no-op. Children always live in the DOM
    /// whether the panel is open or closed.
    /// </summary>
    [Parameter] public bool ForceMount { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool IsOpen => Context.IsOpen(ItemContext.Value);

    private string CssClass => Cx.Merge("text-sm", Class);
}

@namespace Lumeo

@{
    var itemContext = new AccordionItemContext(Value, Disabled, _triggerId, _contentId);
}

<CascadingValue Value="itemContext" IsFixed="false">
    <div class="@CssClass" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter, EditorRequired] public string Value { get; set; } = "";
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Stable IDs per item so AccordionTrigger can render aria-controls
    // pointing at the AccordionContent it discloses, and the content can
    // reflect aria-labelledby back at the trigger. Required by the
    // disclosure pattern; without this pair the screen reader can't
    // announce the relationship.
    private readonly string _triggerId = LumeoIds.New("accordion-trigger");
    private readonly string _contentId = LumeoIds.New("accordion-content");

    private string CssClass => Cx.Merge(
        "border-b border-border/40",
        Cx.When(Disabled, "opacity-50"),
        Class);

    public record AccordionItemContext(string Value, bool Disabled, string TriggerId, string ContentId);
}

@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.IComponentInteropService Interop

@* WAI-ARIA accordion: each trigger button is wrapped in an element with
   role="heading" + aria-level so screen-reader users can navigate the panels by
   heading. role+aria-level (rather than a fixed <h3>) keeps the level configurable
   via HeadingLevel without a dynamic element tag; the wrapper is layout-neutral. *@
<div role="heading" aria-level="@HeadingLevel" class="flex">
    <button type="button"
            id="@ItemContext.TriggerId"
            class="@CssClass"
            aria-expanded="@(IsOpen ? "true" : "false")"
            aria-controls="@ItemContext.ContentId"
            disabled="@IsDisabled"
            @onclick="Toggle"
            @onkeydown="HandleKeyDown"
            @attributes="AdditionalAttributes">
        @ChildContent
        <Blazicon Svg="Lucide.ChevronDown" class="@IconClasses" />
    </button>
</div>

@code {
    [CascadingParameter] public Accordion.AccordionContext Context { get; set; } = default!;
    [CascadingParameter] public AccordionItem.AccordionItemContext ItemContext { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }

    /// <summary>
    /// Heading level (the <c>aria-level</c> on the role="heading" wrapper) so the
    /// accordion's headers sit at the right place in the document outline for
    /// screen-reader heading navigation. Default <c>3</c> (matching the WAI-ARIA
    /// accordion example); set <c>2</c>/<c>4</c>/... to fit the surrounding page.
    /// </summary>
    [Parameter] public int HeadingLevel { get; set; } = 3;

    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool IsOpen => Context.IsOpen(ItemContext.Value);
    private bool IsDisabled => ItemContext.Disabled;
    private string? _registeredValue;
    private bool _pdRegistered;

    protected override void OnParametersSet()
    {
        // Register every parameter set (idempotent) so the parent's roving-focus
        // registry tracks the current value, trigger id and Disabled flag. If
        // the item's Value changed, re-key the EXISTING registry slot in place
        // rather than unregister+register: the latter would RemoveAt the old
        // index then Add the new value to the tail, scrambling the registry out
        // of DOM order and corrupting roving ArrowUp/Down/Home/End nav.
        if (_registeredValue is not null && _registeredValue != ItemContext.Value)
        {
            Context.ReplaceTrigger(_registeredValue, ItemContext.Value, ItemContext.TriggerId, ItemContext.Disabled);
        }
        else
        {
            Context.RegisterTrigger(ItemContext.Value, ItemContext.TriggerId, ItemContext.Disabled);
        }
        _registeredValue = ItemContext.Value;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender || _pdRegistered) return;
        try
        {
            // Suppress page scroll for the roving keys ONLY — a blanket
            // @onkeydown:preventDefault would also swallow Space/Enter (the
            // button's native toggle) and Tab. Key-selective JS preventDefault
            // keeps those working (same pattern as Tabs / Splitter).
            await Interop.RegisterPreventDefaultKeys(
                ItemContext.TriggerId,
                new[] { "ArrowUp", "ArrowDown", "Home", "End" }
                    .Select(k => new PreventDefaultKeyRule(k)).ToArray());
            _pdRegistered = true;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS unavailable during prerender
    }

    public async ValueTask DisposeAsync()
    {
        if (_registeredValue is not null)
            Context.UnregisterTrigger(_registeredValue);
        if (!_pdRegistered) return;
        try { await Interop.UnregisterPreventDefaultKeys(ItemContext.TriggerId); }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }

    private string CssClass => Cx.Merge("flex flex-1 w-full items-center justify-between py-4 text-sm font-medium transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 rounded-sm", (IsDisabled ? "cursor-not-allowed" : "cursor-pointer hover:underline"), Class);

    private string IconClasses => Cx.Join(
        "h-4 w-4 shrink-0 text-muted-foreground transition-transform duration-200",
        Cx.When(IsOpen, "rotate-180"));

    private async Task Toggle()
    {
        if (IsDisabled) return;
        await Context.Toggle.InvokeAsync(ItemContext.Value);
    }

    // WAI-ARIA accordion keyboard model: ArrowDown/ArrowUp move focus between
    // headers (no wrap), Home/End jump to the first/last header. Enter/Space
    // toggle, but the native <button> already does that on keydown, so we don't
    // re-handle them here. preventDefault on the arrows/Home/End stops the page
    // from scrolling while the focus moves.
    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (IsDisabled) return;
        switch (e.Key)
        {
            case "ArrowDown":
                await Context.MoveFocus.InvokeAsync((ItemContext.Value, 1, false, false));
                break;
            case "ArrowUp":
                await Context.MoveFocus.InvokeAsync((ItemContext.Value, -1, false, false));
                break;
            case "Home":
                await Context.MoveFocus.InvokeAsync((ItemContext.Value, 0, true, false));
                break;
            case "End":
                await Context.MoveFocus.InvokeAsync((ItemContext.Value, 0, true, true));
                break;
        }
    }
}
